@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Kanban Board</h1>

@if (isLoading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>Error: @errorMessage</p>
        <button class="btn btn-primary" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    <div class="board-stats">
        <span class="stat-item">Total: <strong>@allTasks.Count</strong></span>
        <span class="stat-item">To Do: <strong>@GetColumnTasks("To Do").Count</strong></span>
        <span class="stat-item">In Progress: <strong>@GetColumnTasks("In Progress").Count</strong></span>
        <span class="stat-item">Done: <strong>@GetColumnTasks("Done").Count</strong></span>
        <span class="stat-item stat-overdue">Overdue: <strong>@allTasks.Count(t => t.DueDate < DateTime.Today)</strong></span>
    </div>

    <div class="board-search">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="searchText" @bind:event="oninput" />
    </div>

    <div class="board-columns">
        @foreach (var column in columns)
        {
            var filtered = GetFilteredColumnTasks(column);
            var colIndex = Array.IndexOf(columns, column);

            <div class="board-column">
                <div class="column-header">
                    <h3>@column</h3>
                    <span class="column-count">@filtered.Count</span>
                </div>

                <div class="column-body">
                    @foreach (var task in filtered)
                    {
                        <div class="task-card">
                            <div class="task-title">@task.Title</div>
                            <div class="task-assignee">@task.Assignee</div>
                            <span class="priority-badge priority-@task.Priority.ToLowerInvariant()">@task.Priority</span>
                            <div class="task-due">@task.DueDate.ToString("MMM dd")</div>
                            <div class="task-actions">
                                @if (colIndex > 0)
                                {
                                    <button class="btn btn-sm btn-outline-secondary"
                                            @onclick="() => MoveTaskAsync(task.Id, columns[colIndex - 1])">
                                        ← Move Left
                                    </button>
                                }
                                @if (colIndex < columns.Length - 1)
                                {
                                    <button class="btn btn-sm btn-outline-secondary"
                                            @onclick="() => MoveTaskAsync(task.Id, columns[colIndex + 1])">
                                        Move Right →
                                    </button>
                                }
                            </div>
                        </div>
                    }
                </div>

                @if (addingToColumn == column)
                {
                    <div class="add-task-form">
                        <input type="text" class="form-control" placeholder="Title"
                               @bind="newTitle" />
                        <input type="text" class="form-control" placeholder="Assignee"
                               @bind="newAssignee" />
                        <select class="form-control" @bind="newPriority">
                            <option value="High">High</option>
                            <option value="Medium">Medium</option>
                            <option value="Low">Low</option>
                        </select>
                        <input type="date" class="form-control" @bind="newDueDate" />
                        <div class="form-buttons">
                            <button class="btn btn-sm btn-primary" @onclick="() => SaveTaskAsync(column)">Save</button>
                            <button class="btn btn-sm btn-secondary" @onclick="CancelAdd">Cancel</button>
                        </div>
                    </div>
                }
                else
                {
                    <button class="btn btn-sm btn-outline-primary add-task-btn" @onclick="() => ShowAddForm(column)">
                        + Add Task
                    </button>
                }
            </div>
        }
    </div>
}

@code {
    private readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private bool isLoading = true;
    private string? errorMessage;
    private string searchText = string.Empty;

    // Add-task form state
    private string? addingToColumn;
    private string newTitle = string.Empty;
    private string newAssignee = string.Empty;
    private string newPriority = "Medium";
    private DateTime newDueDate = DateTime.Today;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasksAsync();
    }

    private async Task LoadTasksAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status)
        => allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> GetFilteredColumnTasks(string status)
    {
        var tasks = GetColumnTasks(status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
        }
        return tasks;
    }

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var task = allTasks.First(t => t.Id == taskId);
            allTasks[allTasks.IndexOf(task)] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private void ShowAddForm(string column)
    {
        addingToColumn = column;
        newTitle = string.Empty;
        newAssignee = string.Empty;
        newPriority = "Medium";
        newDueDate = DateTime.Today;
    }

    private void CancelAdd()
    {
        addingToColumn = null;
    }

    private async Task SaveTaskAsync(string column)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(newTitle, newAssignee, newPriority, newDueDate);
            // The service creates with initial status; update to the target column if different
            if (created.Status != column)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, column);
                created = created with { Status = column };
            }
            allTasks.Add(created);
            addingToColumn = null;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

.board-stats {
    display: flex;
    gap: 1.5rem;
    padding: 0.75rem 1rem;
    background: #f0f4f8;
    border-radius: 8px;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.stat-item {
    font-size: 0.9rem;
}

.stat-overdue strong {
    color: #dc3545;
}

.board-search {
    margin-bottom: 1rem;
    max-width: 400px;
}

.board-error {
    padding: 1rem;
    background: #fff3f3;
    border: 1px solid #dc3545;
    border-radius: 8px;
    margin-bottom: 1rem;
}

.board-columns {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

.board-column {
    flex: 1;
    background: #f6f8fa;
    border-radius: 8px;
    padding: 0.75rem;
    min-width: 0;
    display: flex;
    flex-direction: column;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
    padding-bottom: 0.5rem;
    border-bottom: 2px solid #ddd;
}

.column-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 600;
}

.column-count {
    background: #ddd;
    border-radius: 12px;
    padding: 0.1rem 0.6rem;
    font-size: 0.85rem;
    font-weight: 600;
}

.column-body {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    min-height: 60px;
}

.task-card {
    background: #fff;
    border: 1px solid #e1e4e8;
    border-radius: 6px;
    padding: 0.75rem;
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
}

.task-title {
    font-weight: 600;
    font-size: 0.95rem;
}

.task-assignee {
    font-size: 0.85rem;
    color: #586069;
}

.priority-badge {
    display: inline-block;
    padding: 0.1rem 0.5rem;
    border-radius: 10px;
    font-size: 0.75rem;
    font-weight: 600;
    width: fit-content;
    color: #fff;
}

.priority-high {
    background-color: #dc3545;
}

.priority-medium {
    background-color: #ffc107;
    color: #333;
}

.priority-low {
    background-color: #28a745;
}

.task-due {
    font-size: 0.8rem;
    color: #6a737d;
}

.task-actions {
    display: flex;
    gap: 0.35rem;
    margin-top: 0.25rem;
}

.task-actions .btn {
    font-size: 0.75rem;
    padding: 0.15rem 0.4rem;
}

.add-task-btn {
    margin-top: 0.75rem;
    width: 100%;
}

.add-task-form {
    margin-top: 0.75rem;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    background: #fff;
    border: 1px solid #e1e4e8;
    border-radius: 6px;
    padding: 0.75rem;
}

.add-task-form .form-control {
    font-size: 0.85rem;
    padding: 0.35rem 0.5rem;
}

.form-buttons {
    display: flex;
    gap: 0.5rem;
}

