.board-stats {
    display: flex;
    gap: 1.5rem;
    padding: 0.75rem 1rem;
    background: #f0f4f8;
    border-radius: 8px;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.stat-item {
    font-size: 0.9rem;
}

.stat-overdue strong {
    color: #dc3545;
}

.board-search {
    margin-bottom: 1rem;
    max-width: 400px;
}

.board-error {
    padding: 1rem;
    background: #fff3f3;
    border: 1px solid #dc3545;
    border-radius: 8px;
    margin-bottom: 1rem;
}

.board-columns {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

.board-column {
    flex: 1;
    background: #f6f8fa;
    border-radius: 8px;
    padding: 0.75rem;
    min-width: 0;
    display: flex;
    flex-direction: column;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
    padding-bottom: 0.5rem;
    border-bottom: 2px solid #ddd;
}

.column-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 600;
}

.column-count {
    background: #ddd;
    border-radius: 12px;
    padding: 0.1rem 0.6rem;
    font-size: 0.85rem;
    font-weight: 600;
}

.column-body {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    min-height: 60px;
}

.task-card {
    background: #fff;
    border: 1px solid #e1e4e8;
    border-radius: 6px;
    padding: 0.75rem;
    display: flex;
    flex-direction: column;
    gap: 0.35rem;
}

.task-title {
    font-weight: 600;
    font-size: 0.95rem;
}

.task-assignee {
    font-size: 0.85rem;
    color: #586069;
}

.priority-badge {
    display: inline-block;
    padding: 0.1rem 0.5rem;
    border-radius: 10px;
    font-size: 0.75rem;
    font-weight: 600;
    width: fit-content;
    color: #fff;
}

.priority-high {
    background-color: #dc3545;
}

.priority-medium {
    background-color: #ffc107;
    color: #333;
}

.priority-low {
    background-color: #28a745;
}

.task-due {
    font-size: 0.8rem;
    color: #6a737d;
}

.task-actions {
    display: flex;
    gap: 0.35rem;
    margin-top: 0.25rem;
}

.task-actions .btn {
    font-size: 0.75rem;
    padding: 0.15rem 0.4rem;
}

.add-task-btn {
    margin-top: 0.75rem;
    width: 100%;
}

.add-task-form {
    margin-top: 0.75rem;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    background: #fff;
    border: 1px solid #e1e4e8;
    border-radius: 6px;
    padding: 0.75rem;
}

.add-task-form .form-control {
    font-size: 0.85rem;
    padding: 0.35rem 0.5rem;
}

.form-buttons {
    display: flex;
    gap: 0.5rem;
}

